// DeepLinkHandlerActivity - Entry point for all deep links
class DeepLinkHandlerActivity : Activity() {

    companion object {
        private const val TAG = "DeepLinkHandler"
        const val SCHEME = "myapp"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val uri = intent?.data

        if (uri == null || uri.scheme != SCHEME) {
            Log.e(TAG, "Invalid deep link: $uri")
            Toast.makeText(this, "Invalid link", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        Log.d(TAG, "Handling deep link: $uri")

        val handled = DeepLinkRouter.route(this, uri)

        if (!handled) {
            Log.w(TAG, "Unhandled deep link: $uri")
            Toast.makeText(this, "Unknown link destination", Toast.LENGTH_SHORT).show()
            // Navigate to main activity as fallback
            val fallbackIntent = Intent(this, MainActivity::class.java)
            fallbackIntent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
            startActivity(fallbackIntent)
        }

        finish()
    }
}

// DeepLinkRouter - Routes URIs to appropriate activities
object DeepLinkRouter {

    private const val TAG = "DeepLinkRouter"

    fun route(activity: Activity, uri: Uri): Boolean {
        val host = uri.host
        val pathSegments = uri.pathSegments

        Log.d(TAG, "Routing - host: $host, pathSegments: $pathSegments, query: ${uri.query}")

        return when (host) {
            "profile" -> handleProfile(activity, uri, pathSegments)
            "payment" -> handlePayment(activity, uri, pathSegments)
            "promo" -> handlePromo(activity, uri)
            "home" -> handleHome(activity)
            else -> {
                // Try treating the first path segment as the route if host is null
                when {
                    pathSegments.isNotEmpty() -> routeByPath(activity, uri, pathSegments)
                    else -> false
                }
            }
        }
    }

    // myapp://profile/123 or myapp://profile/123?tab=posts
    private fun handleProfile(activity: Activity, uri: Uri, pathSegments: List<String>): Boolean {
        val userId = if (pathSegments.isNotEmpty()) pathSegments[0] else null
        val tab = uri.getQueryParameter("tab")
        val source = uri.getQueryParameter("utm_source")

        if (userId == null) {
            Log.w(TAG, "Profile deep link missing user ID")
            return false
        }

        val intent = Intent(activity, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            tab?.let { putExtra(ProfileActivity.EXTRA_TAB, it) }
            source?.let { putExtra(ProfileActivity.EXTRA_UTM_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }

        activity.startActivity(intent)
        Log.d(TAG, "Navigating to ProfileActivity with userId=$userId, tab=$tab, source=$source")
        return true
    }

    // myapp://payment/confirm or myapp://payment/confirm?orderId=456&amount=99.99
    private fun handlePayment(activity: Activity, uri: Uri, pathSegments: List<String>): Boolean {
        val action = if (pathSegments.isNotEmpty()) pathSegments[0] else null

        return when (action) {
            "confirm" -> {
                val orderId = uri.getQueryParameter("orderId")
                val amount = uri.getQueryParameter("amount")
                val source = uri.getQueryParameter("utm_source")

                val intent = Intent(activity, PaymentConfirmActivity::class.java).apply {
                    orderId?.let { putExtra(PaymentConfirmActivity.EXTRA_ORDER_ID, it) }
                    amount?.let { putExtra(PaymentConfirmActivity.EXTRA_AMOUNT, it) }
                    source?.let { putExtra(PaymentConfirmActivity.EXTRA_UTM_SOURCE, it) }
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
                }

                activity.startActivity(intent)
                Log.d(TAG, "Navigating to PaymentConfirmActivity with orderId=$orderId, amount=$amount")
                true
            }
            "history" -> {
                val intent = Intent(activity, PaymentHistoryActivity::class.java).apply {
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
                }
                activity.startActivity(intent)
                true
            }
            else -> {
                Log.w(TAG, "Unknown payment action: $action")
                false
            }
        }
    }

    // myapp://promo?code=SUMMER2024&utm_source=email
    private fun handlePromo(activity: Activity, uri: Uri): Boolean {
        val promoCode = uri.getQueryParameter("code")
        val source = uri.getQueryParameter("utm_source")

        val intent = Intent(activity, PromoActivity::class.java).apply {
            promoCode?.let { putExtra(PromoActivity.EXTRA_PROMO_CODE, it) }
            source?.let { putExtra(PromoActivity.EXTRA_UTM_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }

        activity.startActivity(intent)
        Log.d(TAG, "Navigating to PromoActivity with code=$promoCode, source=$source")
        return true
    }

    private fun handleHome(activity: Activity): Boolean {
        val intent = Intent(activity, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        activity.startActivity(intent)
        return true
    }

    private fun routeByPath(activity: Activity, uri: Uri, pathSegments: List<String>): Boolean {
        Log.d(TAG, "Attempting route by path: $pathSegments")
        return false
    }
}

