// ProfileActivity - handles myapp://profile/{userId}
class ProfileActivity : Activity() {

    companion object {
        const val EXTRA_USER_ID = "extra_user_id"
        const val EXTRA_TAB = "extra_tab"
        const val EXTRA_UTM_SOURCE = "extra_utm_source"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val userId = intent.getStringExtra(EXTRA_USER_ID) ?: "unknown"
        val tab = intent.getStringExtra(EXTRA_TAB) ?: "default"
        val source = intent.getStringExtra(EXTRA_UTM_SOURCE)

        // Track analytics
        intent?.data?.let { DeepLinkAnalytics.trackDeepLink(it, "profile") }

        val textView = TextView(this).apply {
            text = "Profile Activity\n\nUser ID: $userId\nTab: $tab\nSource: ${source ?: "direct"}"
            textSize = 20f
            setPadding(48, 48, 48, 48)
        }
        setContentView(textView)

        Log.d("ProfileActivity", "Loaded profile for user: $userId, tab: $tab, source: $source")
    }
}

